<template>
	<view>
		<view class="fab-login-box">
			<view class="item" v-for="(item,index) in servicesList" :key="index"
				@click="item.path?toPage(item.path):login_before(item.id,false)">
				<image class="logo" :src="item.logo" mode="scaleToFill"></image>
				<text class="login-title">{{item.text}}</text>
			</view>
		</view>
	</view>
</template>
<script>
	import config from '@/uni_modules/uni-id-pages/config.js'
	//еүҚдёҖдёӘзӘ—еҸЈзҡ„йЎөйқўең°еқҖгҖӮжҺ§еҲ¶зӮ№еҮ»еҲҮжҚўеҝ«жҚ·зҷ»еҪ•ж–№ејҸжҳҜеҲӣе»әиҝҳжҳҜиҝ”еӣһ
	import {store,mutations} from '@/uni_modules/uni-id-pages/common/store.js'
	let allServicesList = []
	export default {
		computed: {
			agreements() {
				if (!config.agreements) {
					return []
				}
				let {
					serviceUrl,
					privacyUrl
				} = config.agreements
				return [{
						url: serviceUrl,
						title: "з”ЁжҲ·жңҚеҠЎеҚҸи®®"
					},
					{
						url: privacyUrl,
						title: "йҡҗз§Ғж”ҝзӯ–жқЎж¬ҫ"
					}
				]
			},
			agree: {
				get() {
					return this.getParentComponent().agree
				},
				set(agree) {
					return this.getParentComponent().agree = agree
				}
			}
		},
		data() {
			return {
				servicesList: [{
						"id": "username",
						"text": "иҙҰеҸ·зҷ»еҪ•",
						"logo": "/uni_modules/uni-id-pages/static/login/uni-fab-login/user.png",
						"path": "/uni_modules/uni-id-pages/pages/login/login-withpwd"
					},
					{
						"id": "smsCode",
						"text": "зҹӯдҝЎйӘҢиҜҒз Ғ",
						"logo": "/uni_modules/uni-id-pages/static/login/uni-fab-login/sms.png",
						"path": "/uni_modules/uni-id-pages/pages/login/login-withoutpwd?type=smsCode"
					},
					{
						"id": "weixin",
						"text": "еҫ®дҝЎзҷ»еҪ•",
						"logo": "/uni_modules/uni-id-pages/static/login/uni-fab-login/weixin.png",
					},
					// #ifndef MP-WEIXIN
					{
						"id": "apple",
						"text": "иӢ№жһңзҷ»еҪ•",
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/apple.png",
					},
					{
						"id": "univerify",
						"text": "дёҖй”®зҷ»еҪ•",
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/univerify.png",
					},
					{
						"id": "taobao",
						"text": "ж·ҳе®қзҷ»еҪ•", //жҡӮжңӘжҸҗдҫӣиҜҘзҷ»еҪ•ж–№ејҸзҡ„жҺҘеҸЈзӨәдҫӢ
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/taobao.png",
					},
					{
						"id": "facebook",
						"text": "и„ёд№Ұзҷ»еҪ•", //жҡӮжңӘжҸҗдҫӣиҜҘзҷ»еҪ•ж–№ејҸзҡ„жҺҘеҸЈзӨәдҫӢ
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/facebook.png",
					},
					{
						"id": "alipay",
						"text": "ж”Ҝд»ҳе®қзҷ»еҪ•", //жҡӮжңӘжҸҗдҫӣиҜҘзҷ»еҪ•ж–№ејҸзҡ„жҺҘеҸЈзӨәдҫӢ
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/alipay.png",
					},
					{
						"id": "qq",
						"text": "QQзҷ»еҪ•", //жҡӮжңӘжҸҗдҫӣиҜҘзҷ»еҪ•ж–№ејҸзҡ„жҺҘеҸЈзӨәдҫӢ
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/qq.png",
					},
					{
						"id": "google",
						"text": "и°·жӯҢзҷ»еҪ•", //жҡӮжңӘжҸҗдҫӣиҜҘзҷ»еҪ•ж–№ејҸзҡ„жҺҘеҸЈзӨәдҫӢ
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/google.png",
					},
					{
						"id": "douyin",
						"text": "жҠ–йҹізҷ»еҪ•", //жҡӮжңӘжҸҗдҫӣиҜҘзҷ»еҪ•ж–№ејҸзҡ„жҺҘеҸЈзӨәдҫӢ
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/douyin.png",
					},
					{
						"id": "sinaweibo",
						"text": "ж–°жөӘеҫ®еҚҡ", //жҡӮжңӘжҸҗдҫӣиҜҘзҷ»еҪ•ж–№ејҸзҡ„жҺҘеҸЈзӨәдҫӢ
						"logo": "/uni_modules/uni-id-pages/static/app-plus/uni-fab-login/sinaweibo.png",
					}
					// #endif
				],
				univerifyStyle: { //дёҖй”®зҷ»еҪ•еј№еҮәзӘ—зҡ„ж ·ејҸй…ҚзҪ®еҸӮж•°
					"fullScreen": true, // жҳҜеҗҰе…ЁеұҸжҳҫзӨәпјҢtrueиЎЁзӨәе…ЁеұҸжЁЎејҸпјҢfalseиЎЁзӨәйқһе…ЁеұҸжЁЎејҸпјҢй»ҳи®ӨеҖјдёәfalseгҖӮ
					"backgroundColor": "#ffffff", // жҺҲжқғйЎөйқўиғҢжҷҜйўңиүІпјҢй»ҳи®ӨеҖјпјҡ#ffffff
					"buttons": { // иҮӘе®ҡд№үзҷ»еҪ•жҢүй’®
						"iconWidth": "45px", // еӣҫж Үе®ҪеәҰпјҲй«ҳеәҰзӯүжҜ”дҫӢзј©ж”ҫпјү й»ҳи®ӨеҖјпјҡ45px
						"list": []
					},
					"privacyTerms": {
						"defaultCheckBoxState": false, // жқЎж¬ҫеӢҫйҖүжЎҶеҲқе§ӢзҠ¶жҖҒ й»ҳи®ӨеҖјпјҡ true
						"textColor": "#BBBBBB", // ж–Үеӯ—йўңиүІ й»ҳи®ӨеҖјпјҡ#BBBBBB
						"termsColor": "#5496E3", //  еҚҸи®®ж–Үеӯ—йўңиүІ й»ҳи®ӨеҖјпјҡ #5496E3
						"prefix": "жҲ‘е·Ійҳ…иҜ»е№¶еҗҢж„Ҹ", // жқЎж¬ҫеүҚзҡ„ж–ҮжЎҲ й»ҳи®ӨеҖјпјҡвҖңжҲ‘е·Ійҳ…иҜ»е№¶еҗҢж„ҸвҖқ
						"suffix": "е№¶дҪҝз”Ёжң¬жңәеҸ·з Ғзҷ»еҪ•", // жқЎж¬ҫеҗҺзҡ„ж–ҮжЎҲ й»ҳи®ӨеҖјпјҡвҖңе№¶дҪҝз”Ёжң¬жңәеҸ·з Ғзҷ»еҪ•вҖқ
						"privacyItems": []
					}
				}
			}
		},
		watch: {
			agree(agree) {
				this.univerifyStyle.privacyTerms.defaultCheckBoxState = agree
			}
		},
		async created() {
			let servicesList = this.servicesList
			let loginTypes = config.loginTypes

			servicesList = servicesList.filter(item => {

				// #ifndef APP
				//йқһappз«ҜеҺ»жҺүappleзҷ»еҪ•
				if (item.id == 'apple') {
					return false
				}
				// #endif

				// #ifdef APP
				//еҺ»жҺүйқһiosзі»з»ҹдёҠзҡ„appleзҷ»еҪ•
				if (item.id == 'apple' && uni.getSystemInfoSync().osName != 'ios') {
					return false
				}
				// #endif

				return loginTypes.includes(item.id)
			})
			//еӨ„зҗҶдёҖй”®зҷ»еҪ•
			if (loginTypes.includes('univerify')) {
				this.univerifyStyle.privacyTerms.privacyItems = this.agreements
				//и®ҫзҪ®дёҖй”®зҷ»еҪ•еҠҹиғҪеә•дёӢзҡ„еҝ«жҚ·зҷ»еҪ•жҢүй’®
				servicesList.forEach(({
					id,
					logo,
					path
				}) => {
					if (id != 'univerify') {
						this.univerifyStyle.buttons.list.push({
							"iconPath": logo,
							"provider": id,
							path //и·Ҝеҫ„з”ЁдәҺзӮ№еҮ»еҝ«жҚ·жҢүй’®ж—¶еҲӨж–ӯжҳҜи·іиҪ¬йЎөйқў
						})
					}
				})
			}
			//	console.log(servicesList);

			//еҺ»жҺүеҪ“еүҚйЎөйқўеҜ№еә”зҡ„зҷ»еҪ•йҖүйЎ№
			this.servicesList = servicesList.filter(item => {
				let path = item.path ? item.path.split('?')[0] : '';
				return path != this.getRoute(1)
			})
		},
		methods: {
			getParentComponent(){
				// #ifndef H5
				return this.$parent;
				// #endif

				// #ifdef H5
				return this.$parent.$parent;
				// #endif
			},
			setUserInfo(e) {
				console.log('setUserInfo', e);
			},
			getRoute(n = 0) {
				let pages = getCurrentPages();
				if (n > pages.length) {
					return ''
				}
				return '/' + pages[pages.length - n].route
			},
			toPage(path,index = 0) {
				//console.log('жҜ”иҫғ', this.getRoute(1),this.getRoute(2), path)
				if (this.getRoute(1) == path.split('?')[0] && this.getRoute(1) ==
					'/uni_modules/uni-id-pages/pages/login/login-withoutpwd') {
					//еҰӮжһңиҰҒиў«жү“ејҖзҡ„йЎөйқўе·Із»Ҹжү“ејҖпјҢдё”иҝҷдёӘйЎөйқўжҳҜ /uni_modules/uni-id-pages/pages/index/index еҲҷжҠҠзұ»еһӢеҸӮж•°дј з»ҷд»–
					let loginType = path.split('?')[1].split('=')[1]
					uni.$emit('uni-id-pages-setLoginType', loginType)
				} else if (this.getRoute(2) == path) { // еҰӮжһңдёҠдёҖдёӘйЎөйқўе°ұжҳҜпјҢй©¬дёҠиҰҒжү“ејҖзҡ„йЎөйқўпјҢзӣҙжҺҘиҝ”еӣһгҖӮйҳІжӯўйҮҚеӨҚејҖеҗҜ
					uni.navigateBack();
				} else if (this.getRoute(1) != path) {
					if(index === 0){
						uni.navigateTo({
							url: path,
							animationType: 'slide-in-left',
							complete(e) {
								// console.log(e);
							}
						})
					}else{
						uni.redirectTo({
							url: path,
							animationType: 'slide-in-left',
							complete(e) {
								// console.log(e);
							}
						})
					}
				} else {
					console.log('еҮәд№Һж„Ҹж–ҷзҡ„жғ…еҶө,pathпјҡ' + path);
				}
			},
			async login_before(type, navigateBack = true, options = {}) {
				console.log(type);
				//жҸҗзӨәз©әе®һзҺ°
				if (["qq",
						"xiaomi",
						"sinaweibo",
						"taobao",
						"facebook",
						"google",
						"alipay",
						"douyin",
					].includes(type)) {
					return uni.showToast({
						title: 'иҜҘзҷ»еҪ•ж–№ејҸжҡӮжңӘе®һзҺ°пјҢж¬ўиҝҺжҸҗдәӨpr',
						icon: 'none',
						duration: 3000
					});
				}

				//жЈҖжҹҘеҪ“еүҚзҺҜеўғжҳҜеҗҰж”ҜжҢҒиҝҷз§Қзҷ»еҪ•ж–№ејҸ
				// #ifdef APP
				let isAppExist = true
				await new Promise((callback) => {
					plus.oauth.getServices(oauthServices => {
						let index = oauthServices.findIndex(e => e.id == type)
						if(index != -1){
							isAppExist = oauthServices[index].nativeClient
							callback()
						}else{
							return uni.showToast({
								title: 'еҪ“еүҚи®ҫеӨҮдёҚж”ҜжҢҒжӯӨзҷ»еҪ•пјҢиҜ·йҖүжӢ©е…¶д»–зҷ»еҪ•ж–№ејҸ',
								icon: 'none',
								duration: 3000
							});
						}
					}, err => {
						throw new Error('иҺ·еҸ–жңҚеҠЎдҫӣеә”е•ҶеӨұиҙҘпјҡ' + JSON.stringify(err))
					})
				})
				// #endif

				if (
					// #ifdef APP
					!isAppExist
					// #endif

					//йқһappз«ҜдҪҝз”ЁдәҶпјҢappзү№жңүзҷ»еҪ•ж–№ејҸ
					// #ifndef APP
					["univerify","apple"].includes(type)
					// #endif

				) {
					return uni.showToast({
						title: 'еҪ“еүҚи®ҫеӨҮдёҚж”ҜжҢҒжӯӨзҷ»еҪ•пјҢиҜ·йҖүжӢ©е…¶д»–зҷ»еҪ•ж–№ејҸ',
						icon: 'none',
						duration: 3000
					});
				}

				//еҲӨж–ӯжҳҜеҗҰйңҖиҰҒеј№еҮәйҡҗз§ҒеҚҸи®®жҺҲжқғжЎҶ
				let needAgreements = (config?.agreements?.scope || []).includes('register')
				if (type != 'univerify' && needAgreements && !this.agree) {
					let agreementsRef = this.getParentComponent().$refs.agreements
					return agreementsRef.popup(() => {
						this.login_before(type, navigateBack, options)
					})
				}

				// #ifdef H5
				if(type == 'weixin'){
						// console.log('ејҖе§Ӣеҫ®дҝЎзҪ‘йЎөзҷ»еҪ•');
						// let redirectUrl = location.protocol +'//'+
						// 				document.domain +
						// 				(window.location.href.includes('#')?'/#':'') +
						// 				'/uni_modules/uni-id-pages/pages/login/login-withoutpwd?is_weixin_redirect=true&type=weixin'
					// #ifdef VUE2
					const baseUrl = process.env.BASE_URL
					// #endif
					// #ifdef VUE3
					const baseUrl = import.meta.env.BASE_URL
					// #endif

					let redirectUrl = location.protocol +
						'//' +
						location.host +
						baseUrl.replace(/\/$/, '') +
						(window.location.href.includes('#')?'/#':'') +
						'/uni_modules/uni-id-pages/pages/login/login-withoutpwd?is_weixin_redirect=true&type=weixin'
						
					redirectUrl=redirectUrl.replace(location.host,config.webWXAuthBackDomain)

					// console.log('redirectUrl----',redirectUrl);
					let ua = window.navigator.userAgent.toLowerCase();
					if (ua.match(/MicroMessenger/i) == 'micromessenger'){
						// console.log('еңЁеҫ®дҝЎе…¬дј—еҸ·еҶ…');
						return window.open(`https://open.weixin.qq.com/connect/oauth2/authorize?
									appid=${config.appid.weixin.h5}
									&redirect_uri=${encodeURIComponent(redirectUrl)}
									&response_type=code
									&scope=snsapi_userinfo
									&state=STATE&connect_redirect=1#wechat_redirect`);

					}else{
						// console.log('йқһеҫ®дҝЎе…¬дј—еҸ·еҶ…');
						return location.href = `https://open.weixin.qq.com/connect/qrconnect?appid=${config.appid.weixin.web}
										&redirect_uri=${encodeURIComponent(redirectUrl)}
										&response_type=code&scope=snsapi_login&state=STATE#wechat_redirect`
					}
				}
				// #endif

				uni.showLoading({
					mask: true
				})

				if (type == 'univerify') {
					let univerifyManager = uni.getUniverifyManager()
					let clickAnotherButtons = false
					let onButtonsClickFn = async res => {
						console.log('зӮ№еҮ»дәҶз¬¬дёүж–№зҷ»еҪ•пјҢproviderпјҡ', res, res.provider, this.univerifyStyle.buttons.list);
						clickAnotherButtons = true
						let checkBoxState = await uni.getCheckBoxState();
						// еҗҢжӯҘдёҖй”®зҷ»еҪ•еј№еҮәеұӮйҡҗз§ҒеҚҸи®®жЎҶжҳҜеҗҰжү“еӢҫ
						// #ifdef VUE2
						this.agree = checkBoxState[1].state
						// #endif
						// #ifdef VUE3
						this.agree = checkBoxState.state
						// #endif
						let {
							path
						} = this.univerifyStyle.buttons.list[res.index]
						if (path) {
							if( this.getRoute(1).includes('login-withoutpwd') && path.includes('login-withoutpwd') ){
								this.getParentComponent().showCurrentWebview()
							}
							this.toPage(path,1)
							closeUniverify()
						} else {
							if (this.agree) {
								closeUniverify()
								setTimeout(() => {
									this.login_before(res.provider)
								}, 500)
							} else {
								uni.showToast({
									title: "дҪ жңӘеҗҢж„Ҹйҡҗз§Ғж”ҝзӯ–еҚҸи®®",
									icon: 'none',
									duration: 3000
								});
							}
						}
					}

					function closeUniverify() {
						uni.hideLoading()
						univerifyManager.close()
						// еҸ–ж¶Ҳи®ўйҳ…иҮӘе®ҡд№үжҢүй’®зӮ№еҮ»дәӢд»¶
						univerifyManager.offButtonsClick(onButtonsClickFn)
					}
					// и®ўйҳ…иҮӘе®ҡд№үжҢүй’®зӮ№еҮ»дәӢд»¶
					univerifyManager.onButtonsClick(onButtonsClickFn)
					// и°ғз”ЁдёҖй”®зҷ»еҪ•еј№жЎҶ
					return univerifyManager.login({
						"univerifyStyle": this.univerifyStyle,
						success: res => {
							this.login(res.authResult, 'univerify')
						},
						fail(err) {
							console.log(err)
							if(!clickAnotherButtons){
								uni.navigateBack()
							}
							// uni.showToast({
							// 	title: JSON.stringify(err),
							// 	icon: 'none',
							// 	duration: 3000
							// });
						},
						complete: async e => {
							uni.hideLoading()
							//еҗҢжӯҘдёҖй”®зҷ»еҪ•еј№еҮәеұӮйҡҗз§ҒеҚҸи®®жЎҶжҳҜеҗҰжү“еӢҫ
							// this.agree = (await uni.getCheckBoxState())[1].state
							// еҸ–ж¶Ҳи®ўйҳ…иҮӘе®ҡд№үжҢүй’®зӮ№еҮ»дәӢд»¶
							univerifyManager.offButtonsClick(onButtonsClickFn)
						}
					})
				}

				if (type === 'weixinMobile') {
					return this.login({
						phoneCode: options.phoneNumberCode
					}, type)
				}

				uni.login({
					"provider": type,
					"onlyAuthorize": true,
					// #ifdef APP
					"univerifyStyle": this.univerifyStyle,
					// #endif
					success: async e => {
						if (type == 'apple') {
							let res = await this.getUserInfo({
								provider: "apple"
							})
							Object.assign(e.authResult, res.userInfo)
							uni.hideLoading()
						}
						this.login(type == 'weixin' ? {
							code: e.code
						} : e.authResult, type)
					},
					fail: async (err) => {
						console.log(err);
						uni.hideLoading()
					}
				})
			},
			login(params, type) { //иҒ”зҪ‘йӘҢиҜҒзҷ»еҪ•
				// console.log('жү§иЎҢзҷ»еҪ•ејҖе§Ӣ----');
				console.log({params,type});
				//toLowerCase
				let action = 'loginBy' + type.trim().replace(type[0], type[0].toUpperCase())
				const uniIdCo = uniCloud.importObject("uni-id-co",{
					customUI:true
				})
				uniIdCo[action](params).then(result => {
					uni.showToast({
						title: 'зҷ»еҪ•жҲҗеҠҹ',
						icon: 'none',
						duration: 2000
					});
					// #ifdef H5
					result.loginType = type
					// #endif
					mutations.loginSuccess(result)
				})
				.catch(e=>{
					uni.showModal({
						content: e.message,
						confirmText:"зҹҘйҒ“дәҶ",
						showCancel: false
					});
				})
				.finally(e => {
					if (type == 'univerify') {
						uni.closeAuthView()
					}
					uni.hideLoading()
				})
			},
			async getUserInfo(e) {
				return new Promise((resolve, reject) => {
					uni.getUserInfo({
						...e,
						success: (res) => {
							resolve(res);
						},
						fail: (err) => {
							uni.showModal({
								content: JSON.stringify(err),
								showCancel: false
							});
							reject(err);
						}
					})
				})
			}
		}
	}
</script>

